VALUES
  ('locality-d0d1b9a2-moex-00224', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年12月1日與乙客戶約定，將於X2年2月1日以每件價格$800銷售2,000件 商品給乙客戶，並提供自交貨日起為期1年之免費保固服務，該保固屬保證型保固。甲公司 依據過去經驗估計商品於保固期內回廠維修之機率為5%，平均每件商品之維修成本為$300， 而X2年實際保固支出為$25,000。下列敘述何者正確？', '["X1年應認列保固費用$30,000，於X2年底保固負債準備餘額為$5,000", "X1年應認列保固費用$80,000，於X2年底保固負債準備餘額為$55,000", "X2年應認列保固費用$30,000，於X2年底保固負債準備餘額為$5,000", "X1年及X2年皆無須認列負債準備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00225', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初給與10位主管各1,000單位認股權，必須服務4年始能既得，當日認股權 之公允價值每單位$15。於X1年底，因股價下跌，甲公司重設認購價格以維持該認股權計畫 之吸引力，主管仍需服務至 X4 年底才能取得認股權，即既得期間維持不變。價格重設之前 認股權之公允價值每單位$3，而價格重設之後認股權之公允價值每單位$9。甲公司X1年底、 X2年底、X3年底，預期分別有2位、4位、5位主管會在X4年底前離職，X4年底前實際 有5位主管離職，則X4年甲公司應認列之薪資費用為何？', '["$28,750", "$0", "$18,750", "$19,250"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00226', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X10年初同時承攬乙及丙兩間公司的長期工程合約，預計X11年底前皆可完工，甲公 司採用完工百分比法，兩項工程的相關資料如下： 乙公司 丙公司 合約價格 $36,000,000 $27,000,000 X10年已投入工程成本 21,600,000 12,960,000 X10年底估計至完工尚須投入的成本 5,400,000 8,640,000 X10年請款金額 16,200,000 22,500,000 X10年收款金額 10,800,000 19,800,000 在編製甲公司X10年底的財務狀況表時，有關上述兩項合約，流動資產與流動負債餘額之表 達，下列何者正確？', '["流動資產$18,000,000；流動負債$3,600,000", "流動資產$14,400,000；流動負債$0", "流動資產$53,100,000；流動負債$38,700,000", "流動資產$20,700,000；流動負債$6,300,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00227', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列關於無形資產的敘述，正確者共有幾項？', '["非確定耐用年限的無形資產每年須定期測試減損", "尚未可供使用的無形資產每年須提列攤銷費用", "尚未可供使用的無形資產之減損損失未來不得迴轉", "可選擇採用重估價模式作為會計政策 ⑤建立技術可行性前之電腦軟體成本應予以資本化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00228', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年12月1日與乙客戶約定，將於X2年1月1日以每件售價$1,200銷售單位成 本$600的商品共2,000件給乙客戶，除自交貨日起為期1年之免費保證類型保固服務外，若 要加購第2年和第3年的服務型保固，每件商品須另外支付$300，乙客戶於X2年1月1日 選擇每件另外支付$300購買第2年和第3年的保固。甲公司依據過去經驗估計平均每件商品 之維修成本為$500，商品於保固期內第1年回廠維修之機率為5%，第2年維修機率為10%， 第3年維修機率為15%。甲公司以投入法將合約對價分配到履約義務。下列敘述何者正確？', '["X2年認列銷貨收入$2,400,000", "X2年認列保固收入$600,000", "X3年認列保固收入$500,000", "X4年認列保固收入$300,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00229', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司2021年初購入面額$1,000,000之債券投資，票面利率10%，5年期，有效利率為12%， 並分類為按攤銷後成本衡量債券投資。該債券於2022年底有備抵損失$10,000。若甲公司2023 年初改變其管理債券之經營模式，該債券於重分類日公允價值為$930,000，下列有關重分類 之敘述何者正確？', '["重分類前的總帳面金額為$951,963", "若重分類至透過其他綜合損益按公允價值衡量類，則其他權益影響數合計為$11,963（借方）", "若重分類至透過損益按公允價值衡量類，則對損益影響合計為損失$21,963", "若重分類至透過其他綜合損益按公允價值衡量類，則對損益影響合計為損失$10,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00230', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'essay', '查核人員於評估個別項目聲明之固有風險時，如認為該個別項目聲明係
